body:
Greatly stripped down a testbench that runs fine on xcelium to just this:

Example:
```systemverilog
`timescale 1ns / 1ps

typedef struct packed {
    logic [152-2-1:0] hdr;
    logic [2-1:0] vc;
} packet_t;


module dut_tb;

    logic clk;

    typedef struct {packet_t [2-1:0] pkt_i;} dut_if_t;

    dut_if_t dut[2];

    initial begin
        clk = 0;
        forever #(0.5) clk = ~clk;
    end

    task automatic send_req_packets(int module_id, int channel);

        packet_t packet = '0;

        dut[module_id].pkt_i[channel] = packet;

        @(posedge clk);  // If you comment out this line. It will build.
    endtask

    initial begin
        for (int m = 0; m < 2; m++) begin

            for (int i = 0; i < 2; i++) begin
                automatic int mod = m;
                automatic int ch = i;
                send_req_packets(mod, ch);
            end
        end


        $finish;
    end

endmodule
```
